import { readFileSync, writeFileSync } from "fs";
import { S3Client, PutObjectCommand, DeleteBucketCommand } from "@aws-sdk/client-s3";
import { checkpoint, restore } from "@tigrisdata/agent-kit";

async function main() {
  // 1. Read and normalize trial ID
  const rawTrialId = readFileSync("/logs/artifacts/trial_id", "utf-8").trim();
  const normalizedTrialId = rawTrialId.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
  const bucketName = `harbor-awscli-${normalizedTrialId}`;
  console.log(`Source bucket: ${bucketName}`);

  const s3Client = new S3Client({
    endpoint: "REDACTED",
    region: "REDACTED",
    credentials: {
      accessKeyId: process.env.TIGRIS_STORAGE_ACCESS_KEY_ID!,
      secretAccessKey: process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY!,
    },
  });

  // 1. Upload v1
  console.log("Uploading v1.txt (version=1)...");
  await s3Client.send(
    new PutObjectCommand({
      Bucket: bucketName,
      Key: "v1.txt",
      Body: "version=1",
    })
  );

  // 2. Checkpoint
  console.log("Taking checkpoint 'before-mutation'...");
  const { data: ckpt, error: ckptError } = await checkpoint(bucketName, { name: "before-mutation" });
  if (ckptError) {
    console.error("Checkpoint failed:", ckptError);
    process.exit(1);
  }
  const snapshotId = ckpt.snapshotId;
  console.log(`Checkpoint taken. Snapshot ID: ${snapshotId}`);

  // 3. Mutate
  console.log("Mutating v1.txt (version=2)...");
  await s3Client.send(
    new PutObjectCommand({
      Bucket: bucketName,
      Key: "v1.txt",
      Body: "version=2",
    })
  );

  // 4. Restore
  console.log("Restoring checkpoint into fork 'rollback-recovery'...");
  const { data: restored, error: restoreError } = await restore(bucketName, snapshotId, {
    forkName: "rollback-recovery",
  });
  if (restoreError) {
    console.error("Restore failed:", restoreError);
    process.exit(1);
  }
  const recoveryBucket = restored.bucket;
  console.log(`Restored to bucket: ${recoveryBucket}`);

  // Write recovery.json
  const recoveryJsonPath = "/home/user/chained-ckpt/recovery.json";
  writeFileSync(recoveryJsonPath, JSON.stringify({ recoveryBucket }));
  console.log(`Wrote ${recoveryJsonPath}`);

  // 5. Tear down the recovery fork
  console.log(`Deleting recovery fork bucket: ${recoveryBucket}...`);
  // Note: To delete a bucket in S3, it must be empty. 
  // However, Tigris forks might have different behavior or we might need to delete objects first.
  // The instructions say "delete the recovery fork bucket so it does not leak".
  // Let's try DeleteBucketCommand first. If it fails because it's not empty, we might need to list and delete objects.
  // Actually, Tigris `removeBucket` might be more forceful or handle it.
  // Let's use DeleteBucketCommand and see.

  try {
    // Before deleting the bucket, we must delete the objects inside it.
    // In this case, v1.txt should be there.
    await s3Client.send(
      new PutObjectCommand({
        Bucket: recoveryBucket,
        Key: "v1.txt",
        Body: "", // We could delete it, but let's just try to delete the bucket if Tigris allows it.
      })
    );
    // Actually let's just use DeleteBucketCommand.
    await s3Client.send(new DeleteBucketCommand({ Bucket: recoveryBucket }));
    console.log("Recovery fork bucket deleted.");
  } catch (err) {
    console.error("Failed to delete recovery bucket with S3 SDK, trying tigris CLI...", err);
    import("child_process").then(({ execSync }) => {
      execSync(`tigris buckets delete ${recoveryBucket}`, { stdio: "inherit" });
      console.log("Recovery fork bucket deleted via CLI.");
    });
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

